  ('locality-7ec62a85-moex-00052', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '經濟部智慧財產局訂頒商標識別性審查基準，如甲文創公司認經營環境受到限制，不服該審查基 準，關於其救濟，下列敘述何者正確？', '["甲得逕向憲法法庭聲請宣告該審查基準為違憲", "甲得逕向高等行政法院起訴請求撤銷該審查基準", "甲得請求行政法院聲請憲法法庭宣告該審查基準違憲", "需由經濟部智慧財產局依該審查基準對甲作成處分後，甲始得對該處分提起訴願、行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00053', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '關於訴願期間行政處分停止執行之敘述，下列何者錯誤？', '["訴願人於訴願程序終結前，亦得向行政法院聲請停止執行", "原行政處分之執行，原則上不因提起訴願而停止", "訴願人僅得就原行政處分之全部聲請停止執行，以維護行政權之完整性", "受理訴願機關認為原行政處分之合法性顯有疑義，得依職權命原處分機關停止執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00054', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '甲為公益團體，認為A工廠長年違法傾倒廢棄物，致使周遭農地受到污染，遂依廢棄物清理法規 定，以書面向當地主管機關乙請求依法行使公權力。若乙未在法定期間內採取任何作為，而甲欲 依行政訴訟法規定提起公益訴訟時，下列敘述何者正確？', '["本案仍應視其具體主張而提起特定訴訟類型", "甲必須證明自身權益亦遭受損害，始得提起本案訴訟", "向行政法院提起訴訟前，一律須經訴願程序", "此種訴訟屬於備位性質，必須限於無法提起其他行政訴訟時，始得提起"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00055', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["提起一般給付訴訟應經訴願先行程序", "提起都市計畫審查程序應向都市計畫區所在地之高等行政法院為之", "公職人員選舉罷免法明定之選舉訴訟係向行政法院提起", "不服律師懲戒委員會作成之懲戒處分係向行政法院提起訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00056', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '關於賠償義務機關，下列敘述何者正確？', '["公共設施委託民間團體管理時，因管理欠缺致人民生命受有損害者，以該民間團體為賠償義務 機關", "受託行使公權力之團體，其執行職務之人於行使公權力時所生之國家賠償責任，以該團體為賠 償義務機關", "賠償義務機關經裁撤或改組者，原則上應優先以其裁撤或改組前之上級機關為賠償義務機關", "無法確定賠償義務機關而請求上級機關確定，上級機關逾期不為確定者，得逕以該上級機關為 賠償義務機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00057', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '下列何種情形，國家應負損害賠償責任？', '["各級政府機關依中央流行疫情指揮中心指揮官之指示，徵用私立醫療機構設立檢疫場所", "既成道路或都市計畫道路用地，在依法徵收或價購前所埋設之地下設施，致妨礙土地權利人對 其權利之行使", "私人建築物被指定為古蹟，致所有權人無法為使用收益", "土地因地政機關登記遺漏，致人民無法主張權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00058', 'locality-7ec62a85', 'locality-7ec62a85-moex-113-de0a21a2', 'sub-locality-7ec62a85-01', NULL, 'essay', '通緝犯甲於某日夜晚駕車行駛，突然遇到警察設置的臨檢點。警察 A示
意甲停車接受臨檢。甲擔心被發現，決定不配合檢查，並立即開車試圖
逃離現場。A見狀後試圖打開車門並抓住方向盤以阻止甲逃跑。甲不顧
A 的阻止，繼續加速行駛，A被迫緊抓方向盤，隨著車輛的加速而被拖
行十餘公尺，A頭部撞擊地面數次，最終死亡。請問：甲所涉的刑事責
任為何？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "be75df8d255e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "316", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00059', 'locality-7ec62a85', 'locality-7ec62a85-moex-113-de0a21a2', 'sub-locality-7ec62a85-01', NULL, 'essay', '甲任職於衛生福利部某醫院總務處負責採購業務。他與 A醫材廠商的業
務經理乙熟識，經常接受乙提供的餐飲與旅遊招待。丙為該醫院某科的
兼職主治醫師，於負責病患門診看診、手術等業務外，亦有參與該院採
購權限。甲、乙針對本次醫療儀器採購達成合意，乙提供120萬給具實
質決定權的丙，並由甲代轉給丙，甲則設法說服丙使 A廠商得標。雖然
丙認為 B廠商的醫療儀器更為合適，但甲仍成功說服丙於提出該科需求
與訂立採購規格功能時將條件限定於 A廠商的醫療儀器，並於驗收時給
予方便。甲並向丙表示：「如果醫院最終購買該廠商產品，保證 A 廠商
會贊助丙一筆技術研究費。」在購案得標訂立採購契約之隔日，乙即依
約定將 120萬元轉入甲帳戶，委由甲交給丙。然而甲僅交付 100萬元現
金給丙，另外 20 萬元則據為己有。之後丙使用該 100 萬元購買實驗材
料進行研究，並撰寫論文發表。請問：甲、乙、丙可能涉及的刑事責任
為何？（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "be75df8d255e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "316", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00060', 'locality-7ec62a85', 'locality-7ec62a85-moex-113-de0a21a2', 'sub-locality-7ec62a85-01', NULL, 'essay', '甲之女 A疑被乙強制猥褻。甲氣憤不過，為蒐集證據，未經乙同意，錄
製了甲、乙之間的對話，後提出給檢警官員。審判中，乙主張甲的錄音
